	.SBTTL	ICOLIST; Recherche dans SYS_LIST selon un critre; ----------------------------------------;--------\; INISRC  >;========/; Dbut d'une recherche dans SYS_LIST.; in	A0.L	^critre de recherche;	A1.L	^nom(s) par dfaut(s); out	A0.L	^plus loin dans critre;	D7.W	erreur; mod	D7.W, A0.LINISRC:	PUSHM.L	D1,D3,D4,D6,A3,A4	CLR.W	(A6)+OSRCNN	LOAD.W	D7,#ERSYNT	; D7 <-- erreur de syntaxe	LOAD.L	A3,#(A6)+OBUNAM10$:	COMP.B	(A0),#'@	JUMP',EQ 20$	COMP.B	(A0),#'#	JUMP',NE 30$20$:	LOAD.B	D3,(A0+)	JUMP,EQ	90$	COMP.B	D3,#CR	JUMP,EQ	90$	LOAD.B	(A3+),D3	; OBUNAM <-- unit:	COMP.B	D3,#':	JUMP,NE	20$	JUMP	10$30$:	LOAD.L	A4,#R16"NAMLST40$:	LOAD.B	(A3+),(A4+)	; OBUNAM <-- SYS_LIST	JUMP,NE	40$	CLR.W	(A6)+OSRCDF	; pas de noms par dfaut	LOAD.L	A3,A1		; A3 <-- ^nom(s) par dfaut(s)45$:	COMP.B	(A3),#'"	JUMP',NE 50$	INC.W	(A6)+OSRCDF	; un nom par dfaut de plus	CALL	SKPNPD		; A3 <-- ^nom par dfaut suivant	JUMP,EQ	45$50$:	CLR.W	(A6)+OSRCCH	COMP.B	(A0),#'"	; qq chose  lister ?	JUMP',EQ 80$		; non => 80$	LOAD.L	A3,#(A6)+OBUNAM	; A3 <-- ^[unit:]SYS_LIST	LOAD.W	D3,#2^BOPRD	; D3 <-- mode d'ouverture	FOS	?OPEN		; ouvre SYS_LIST	JUMP',NE 90$	LOAD.W	(A6)+OSRCCH,D6	; mmorise canal	CLR.W	(A6)+OSRCCP	; nb restant dans OSRCBL	CLR.W	(A6)+OSRCCB	LOAD.L	D4,#MAXNBL*LGBLK	LOAD.W	D1,#MTYPCP	GESMEM	?GETMEM		; demande mmoire pour buffer	JUMP',NE 90$	LOAD.L	(A6)+OSRCPB,A480$:	LOAD.L	D4,#MAXSRC+1	; +1 pour <0> terminateur	LOAD.W	D1,#MTYPCP	GESMEM	?GETMEM		; demande mmoire pour noms	JUMP',NE 90$	LOAD.L	(A6)+OSRCPN,A4	CALL	RAZSRC90$:	POPM.L	D1,D3,D4,D6,A3,A4	TEST.W	D7		; retour EQ/NE	RET;--------\; RAZSRC  >;========/; Remet  zro la recherche pour une "page" suivante.; in	-; out	-; mod	-RAZSRC:	PUSH.L	A4	CLR.W	(A6)+OSRCNN	LOAD.L	A4,(A6)+OSRCPN	LOAD.L	(A6)+OSRCPP,A4	CLR.B	(A4)		; met le <0> terminateur	LOAD.W	(A6)+OSRCCD,(A6)+OSRCDF ; arme compteur nom(s) par dfaut(s)	POP.L	A4	RET;--------\; NXTSRC  >;========/; Cherche le fichier suivant dans SYS_LIST.; in	A0.L	^critre de recherche;	A1.L	^noms par dfauts; out	A3.L	^nom trouv;	A4.L	^arguments;	D7.W	erreur; mod	A3.L, A4.L, D7.WNXTSRC:	PUSHM.L	D3,D4,D6,A1,A210$:	LIB	?IFCAR		; touche presse ?	JUMP',NE 20$		; non => 20$	CALL	FILTRE		; filtre touche souris	LOAD.W	D7,#EROUTF	; D7 <-- c'est fini	COMP.B	D3,#END	JUMP,EQ	90$	COMP.B	D3,#F0	JUMP,EQ	90$	COMP.B	D3,#F0+SHIFT	JUMP,EQ	90$	LOAD.W	D7,#1		; D7 <-- excute tout de suite	COMP.B	D3,#CR		; 2x (RETURN) ?	JUMP,EQ	90$	COMP.W	D3,#KEYMGP	; 2x "clic" souris rapide ?	JUMP,EQ	90$20$:	TEST.W	(A6)+OSRCCD	; encore un nom par dfaut ?	JUMP',EQ 25$		; non => 25$				; oui =>	LOAD.L	A3,A1		; A3 <-- ^nom(s) par dfaut(s)	LOAD.L	A4,#0		; A4 <-- pas d'arguments	LOAD.W	D3,(A6)+OSRCDF	; D3 <-- nb total de "npd"	SUB.W	D3,(A6)+OSRCCD	; D3 <-- rang du "ndp"	DEC.W	(A6)+OSRCCD	; un de moins22$:	TEST.W	D3		; rang "ndp" trouv ?	JUMP,EQ	60$		; oui => 60$	CALL	SKPNPD		; A3 <-- ^"npd" suivant	DEC.W	D3	JUMP	22$25$:	LOAD.W	D7,#EROUTF	; D7 <-- c'est fini	TEST.W	(A6)+OSRCCH	; qq chose  lister ?	JUMP,EQ	90$		; non => 90$	TEST.W	(A6)+OSRCCP	; reste qq chose dans OSRCBL ?	JUMP,NE 50$		; oui => 50$	LOAD.W	(A6)+OSRCCP,#NBFLST	TEST.W	(A6)+OSRCCB	; encore un bloc dj lu ?	JUMP,NE	40$		; oui => 40$				; non =>	LOAD.W	D6,(A6)+OSRCCH	; D6 <-- canal	LOAD.L	A4,(A6)+OSRCPB	; A4 <-- ^buffer de bloc	LOAD.L	D4,#MAXNBL*LGBLK	FOS	?RDBYTE		; lit nouveaux blocs	JUMP',EQ 35$		; ok => 35$	COMP.W	D7,#EROUTF	; fin du fichier ?	JUMP',NE 30$		; non => 30$	TEST.L	D4		; qq chose lu ?	JUMP',NE 	35$		; oui => 35$30$:	CALL	ENDSRC		; ferme SYS_LIST	JUMP	90$35$:	LOAD.L	(A6)+OSRCPT,A4	; init ^dbut des blocs lus	DIV.WU	D4,#LGBLK	; D4 <-- nb blocs lus	LOAD.W	(A6)+OSRCCB,D4	JUMP'	45$40$:	ADD.L	(A6)+OSRCPT,#LGBLK-(NBFLST*LGBL)45$:	DEC.W	(A6)+OSRCCB	; un bloc de moins50$:	LOAD.L	A4,(A6)+OSRCPT	; A4 <-- ^nom de fichier	ADD.L	(A6)+OSRCPT,#LGBL ; ^suivant dans OSRCBL	DEC.W	(A6)+OSRCCP	; un fichier de moins	TEST.B	(A4)		; fichier dans BL ?	JUMP,EQ 10$		; non => 10$				; oui =>	LOAD.L	A3,A0		; A3 <-- ^chane "-" et "*"	LOAD.L	A2,#R16"LSTTERM	; A2 <-- ^liste de terminateurs	LIB	?CPSTRING	; fichier ok ?	JUMP,NS 10$		; non => 10$				; oui =>	LOAD.L	A3,A4		; A3 <-- ^nom trouv	LOAD.L	A4,#(A4)+OBLTYP	; A4 <-- ^arguments;;?	LOAD.L	D4,(A4)+OBAATT	; D4 <-- attributs;;?	TEST.L	D4:#BATTL	; attribut "L" prsent ?;;?	JUMP,BC	10$		; non => 10$	LOAD.L	D3,(A6)+OSRCPP	SUB.L	D3,(A6)+OSRCPN	; D3 <-- lg utilise	COMP.L	D3,#MAXSRC	; buffer_nom plein ?	JUMP',HS 80$		; oui => 80$60$:				; non =>	COMP.B	(A3),#'"	; nom commence par guillemet ?	JUMP',NE 65$		; non => 65$	INC.L	A3		; oui => saute-le65$:	LOAD.L	A2,A3		; A2 <-- ^nom	LOAD.L	A1,(A6)+OSRCPP	; A1 <-- ^dans buffer	LOAD.B	D3,#1670$:	LOAD.B	(A1+),(A2+)	; buffer_nom <-- nom trouv	DEC.B	D3	JUMP,NE	70$	CLR.B	(A1)		; remet le terminateur	LOAD.L	(A6)+OSRCPP,A1	INC.W	(A6)+OSRCNN80$:	CLR.W	D7		; D7 <-- ok90$:	POPM.L	D3,D4,D6,A1,A2	TEST.W	D7		; retour EQ/NE	RET;--------\; ENDSRC  >;========/; Termine une recherche dans SYS_LIST.; in	-; out	-; mod	-ENDSRC:	PUSHM.L	D1,D6,D7,A4	LOAD.W	D6,(A6)+OSRCCH	; D6 <-- canal de SYS_LIST	JUMP',EQ 50$	FOS	?CLOSE		; ferme SYS_LIST	CLR.W	(A6)+OSRCCH	; plus de canal !50$:	LOAD.L	D6,(A6)+OSRCPB	JUMP',EQ 60$	LOAD.L	A4,D6	LOAD.W	D1,#MTYPCP	GESMEM	?GIVMEM		; rend le buffer	CLR.L	(A6)+OSRCPB	; plus de buffer !60$:	LOAD.L	D6,(A6)+OSRCPN	JUMP',EQ 90$	LOAD.L	A4,D6	LOAD.L	(A6)+OSRCPP,A4	LOAD.W	D1,#MTYPCP	GESMEM	?GIVMEM		; rend le buffer	CLR.L	(A6)+OSRCPN	; plus de buffer !90$:	POPM.L	D1,D6,D7,A4	RET;--------\; SKPNPD  >;========/; Saute un nom par dfaut.; in	A3.L	^nom par dfaut; out	A3.L	^nom par dfaut suivant;	D7.W	erreur; mod	D7.W, A3.LSKPNPD:	PUSH.W	D3	LOAD.W	D7,#1		; D7 <-- suivant n'existe pas	COMP.B	(A3+),#'"	; commence par guillemet ?	JUMP',NE 90$		; non => 90$10$:	LOAD.B	D3,(A3+)	; A3 <-- cherche fin du "npd"	JUMP',EQ 90$	COMP.B	D3,#CR	JUMP',EQ 90$	COMP.B	D3,#']	JUMP',EQ 90$	COMP.B	D3,#'"	JUMP,NE	10$20$:	LOAD.B	D3,(A3+)	; A3 <-- cherche dbut "npd" suivant	JUMP',EQ 90$	COMP.B	D3,#CR	JUMP',EQ 90$	COMP.B	D3,#']	JUMP',EQ 90$	COMP.B	D3,#SPACE	JUMP,EQ	20$	COMP.B	D3,#TAB	JUMP,EQ	20$	COMP.B	D3,#'"	JUMP',NE 90$	DEC.L	A3	CLR.W	D7		; D7 <-- trouv90$:	POP.W	D3	TEST.W	D7		; retour EQ/NE	RET	.END